"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[218],{8837:(e,o,t)=>{t.r(o),t.d(o,{search:()=>a});let n=new(t(4246)).Ay.Document({tokenize:"full",document:{id:"url",index:"content",store:["title","pageTitle"]},context:{resolution:9,depth:2,bidirectional:!0}});for(let{url:e,sections:o}of[{url:"/",sections:[["Getting started",null,["A curated list of extensions, Python packages, machine-learning workflows, and collaborative notebooks ready to run in Deepnote — the modern data-science notebook with real-time collaboration and one-click sharing."]],["What is Deepnote?","what-is-deepnote",["Deepnote is a Jupyter-compatible notebook with real-time collaboration, easy deployment, and built-in dataset connectors. Think of it as Google Docs for data scientists — without giving up your Python kernel or your ."]],["What is this list?","what-is-this-list",["Everything here is something you can either open in Deepnote with one click, or install/learn from inside a Deepnote project. The original curation began in 2020 as a community effort and continues to grow.","The full source is on GitHub at ramene/awesome-deepnote under Creative Commons Attribution 4.0 — PRs welcome."]],["Quick start","quick-start",["Open any notebook below with the Launch in Deepnote badge, or paste any public GitHub notebook URL into Deepnote's launch endpoint:","Need more depth? Browse the sidebar by category, or jump straight to Books & journals for full-length tutorials."]]]},{url:"/docs/about",sections:[["About Deepnote",null,["Deepnote is a Jupyter-compatible notebook with real-time collaboration, easy deployment, and built-in dataset connectors. It launched out of YC with Index Ventures + Accel leading the seed round and has since grown into a default tool for many data-science teams."]],["Why it's different","why-its-different",["Most notebook environments make collaboration an afterthought — you commit to a repo, your collaborator pulls, you both run a kernel that may or may not produce the same outputs. Deepnote treats collaboration as primary:"]],["Where it fits","where-it-fits",[]],["Compatibility","compatibility",["Deepnote runs the standard IPython kernel. Any notebook that opens in Jupyter will open in Deepnote — you can paste a GitHub URL into the launch endpoint:"]],["License","license",["The awesome-deepnote list itself is published under Creative Commons Attribution 4.0. The Deepnote platform is a separate commercial product — see deepnote.com."]]]},{url:"/docs/awesome-lists",sections:[["Other awesome lists",null,["The awesome-list pattern started with awesome on GitHub. Below are the lists most adjacent to Deepnote's audience — Python, data science, ML, visualization, and the broader awesome ecosystem."]],["General-purpose","general-purpose",[]],["Python & data science","python-and-data-science",[]],["Machine learning","machine-learning",[]],["Datasets & visualization","datasets-and-visualization",[]],["Cloud / infra","cloud-infra",[]],["Reference","reference",[]],["Find more","find-more",["Search GitHub for #awesome or #awesome-lists for the full constellation."]]]},{url:"/docs/contributing",sections:[["Contributing",null,["awesome-deepnote is community-maintained. Anything you add here helps the next person find a working notebook faster."]],["What belongs here","what-belongs-here",[]],["What doesn't belong","what-doesnt-belong",[]],["How to contribute","how-to-contribute",["Entry format","If the notebook has a Deepnote launch button:"]],["What happens after the PR","what-happens-after-the-pr",["Maintainer reviews for: link is alive, notebook actually runs, category fit, no duplicates. If it's a clean add, it merges within a few days. The site you're reading is auto-rebuilt from the README on every push to ."]],["License","license",["By contributing, you agree your additions are released under the same Creative Commons Attribution 4.0 license as the rest of the list."]]]},{url:"/docs/in-the-media",sections:[["In the media",null,["External coverage of Deepnote — reviews, case studies, and press."]],["Reviews & analysis","reviews-and-analysis",["Reviewing Deepnote — The New IDE for Data Scientists — Towards Data Science take. Comparative review covering UX, collaboration, and pricing.","Deepnote: the modern way to teach Data Science — Educator perspective, focused on classroom use."]],["Case studies","case-studies",[]],["Company / funding","company-funding",[]]]},{url:"/docs/integrations",sections:[["Integrations",null,["Packages and tooling that bridge Deepnote with the rest of the data-science ecosystem."]],["Featured","featured",[]],["Patterns","patterns",["These are conceptual integrations rather than packages — common ways to wire Deepnote into a larger workflow:","Have an integration to add? Open a PR — see Contributing."]]]},{url:"/docs/resources",sections:[["Resources",null,["Community and tooling resources for Deepnote users."]],["Community","community",[]],["Tools","tools",[]],["Official","official",[]]]},{url:"/docs/notebooks/books-journals",sections:[["Books & journals",null,["Multi-chapter curricula and reference texts, all runnable in Deepnote. These are the long reads — pick one, work through it project by project."]],["Courses","courses",["Intro to Deep Learning by Ryan Holbrook @ Kaggle — Beginner-friendly path through Keras + tabular DL.","Datascience IPython Notebooks by Donne Martin — A large curated index covering pandas, NumPy, scikit-learn, TensorFlow, AWS, and command-line data tools."]],["Books","books",["Maths: Form and Function with Python by James G. Hill — Notebooks accompanying the Mathematics: Form and Function text. Mathematical foundations rendered as runnable code.","Probabilistic Programming and Bayesian Methods for Hackers — The Bayesian-methods-for-hackers book, every chapter as a notebook. PyMC3-based.→ Launch prologue","Python for Probability, Statistics, and Machine Learning 2E — Companion notebooks. Heavier on stats theory than most ML books.→ Launch ML intro chapter","Mining the Social Web by Mikhail Klassen — Twitter, Facebook, LinkedIn, Instagram, GitHub, web scraping. The third edition is current with modern APIs.→ Launch preface"]]]},{url:"/docs/notebooks/conda",sections:[["Anaconda & Conda in Deepnote",null,["Deepnote's default environment is -based, but you can layer Conda on top for packages that need it (think GDAL, OpenCV with custom CUDA, or anything with C++ deps that fights pip)."]],["Featured","featured",[]],["Common gotchas","common-gotchas",[]]]},{url:"/docs/notebooks/matplotlib-plotly",sections:[["Matplotlib & Plotly notebooks",null,["Notebooks centered on visualization — matplotlib, plotly, and adjacent plotting libraries. Open with one click and explore the underlying data."]],["Featured","featured",[]],["See also","see-also",[]]]},{url:"/docs/notebooks/ml-frameworks",sections:[["scikit-learn, TensorFlow & Keras",null,["The core ML stack on Deepnote: scikit-learn for classical ML, TensorFlow / Keras for deep learning. Each notebook below opens directly in Deepnote with one click."]],["Applied projects","applied-projects",["Detect Credit Card Fraud — End-to-end scikit-learn classifier on the canonical Kaggle fraud dataset. Imbalanced-class handling included.→ Launch in Deepnote","Customer Churn Prediction — Classical ML pipeline (feature engineering → model selection → evaluation) on a telecom churn dataset.→ Launch in Deepnote"]],["Books with end-to-end notebooks","books-with-end-to-end-notebooks",["Hands-on Machine Learning with Scikit-Learn and TensorFlow — Aur\xe9lien G\xe9ron's reference text. Every chapter ships a runnable notebook from ageron/handson-ml.→ Launch chapter 2 (end-to-end project)","Deep Learning with TensorFlow 2 and Keras — Companion course material. Practical, focused on TF2 idioms."]],["See also","see-also",[]]]},{url:"/docs/notebooks/tensorboard",sections:[["TensorBoard in Deepnote",null,["TensorBoard runs as a sub-process inside a Deepnote project. The trick is exposing its port to your browser — these notebooks cover the common patterns."]],["Featured","featured",["TensorBoard with ngrok — Tunnel TensorBoard's dashboard through ngrok so you can view it from outside the Deepnote project. Useful when iframe-embedding doesn't render.","Scraping the EPL Stats Website — A non-ML project that demonstrates the same long-running-service pattern (scraper + persistent state). The docs walk through Deepnote project structure."]],["Quick reference","quick-reference",["If the inline  magic doesn't render, fall back to the ngrok pattern from the notebook above."]]]}])for(let[t,a,i]of o)n.add({url:e+(a?"#"+a:""),title:t,content:[t,...i].join("\n"),pageTitle:a?o[0][0]:void 0});function a(e,o={}){let t=n.search(e,{...o,enrich:!0});return 0===t.length?[]:t[0].result.map(e=>({url:e.id,title:e.doc.title,pageTitle:e.doc.pageTitle}))}}}]);